// // This module selects one of the six 4-bit data inputs based on a 3-bit selection input. For selection values 0 to 5, it outputs the corresponding data input. However, when sel is 6 or 7, it performs a bitwise OR operation on the least significant 2 bits of all six data inputs and replicates this 2-bit result to form a 4-bit output.
module top_module( 
    input [2:0] sel, 
    input [3:0] data0,
    input [3:0] data1,
    input [3:0] data2,
    input [3:0] data3,
    input [3:0] data4,
    input [3:0] data5,
    output reg [3:0] out
);reg [1:0] and_result;

always @* begin
    case (sel)
        3'b000: out = data0;
        3'b001: out = data1;
        3'b010: out = data2;
        3'b011: out = data3;
        3'b100: out = data4;
        3'b101: out = data5;
        3'b110, 3'b111: begin
            and_result = data0[1:0] & data1[1:0] & data2[1:0] & data3[1:0] & data4[1:0] & data5[1:0];
            out = {and_result, and_result};
        end
    endcase
end

endmodule
